from math import comb, isqrt
from functools import lru_cache
from sympy import mobius
def A309192(n):
    @lru_cache(maxsize=None)
    def g(x): return mobius(x)
    def f(x): return sum(g(i)*i**2*comb(x//i**2+1,2) for i in range(1,isqrt(x)+1))
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k*(f(m)-f(j-1))
        j = m+1
    return c # _Chai Wah Wu_, May 21 2026

